import{_ as t,o as a,c as o,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"180. Study Leave","description":"","frontmatter":{"title":"180. Study Leave","eba":"Mental Health Services 2024-2028","topics":["leave","study-leave","preliminary","education-pd"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/180-study-leave.md","filePath":"ebas/mental-health/support-services/preliminary/180-study-leave.md"}'),r={name:"ebas/mental-health/support-services/preliminary/180-study-leave.md"};function n(l,e,i,p,d,u){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="_180-study-leave" tabindex="-1">180. Study Leave <a class="header-anchor" href="#_180-study-leave" aria-label="Permalink to &quot;180. Study Leave&quot;">​</a></h1><p><strong>180.1</strong> Employee will be entitled to four (4) hours paid study leave per week up to a maximum of 26 weeks per annum, where undertaking study at Australian Qualification Framework Level 3 or above with an education institution or approved provider.</p><p><strong>180.2</strong> Paid study leave may be taken as mutually agreed by, for example, 4 hours per week, 8 hours per fortnight or in blocks of 38 hours.</p><p><strong>180.3</strong> A part-time Employee shall be entitled to paid study leave on a pro-rata basis.</p><p><strong>180.4</strong> An Employee wishing to take study leave must apply in writing to the Employer as early as possible prior to the proposed leave date. The Employee’s request should include:</p><p><strong>(a)</strong> details of the course and institution in which the Employee is enrolled, or proposes to enrol; and</p><p><strong>(b)</strong> details of the relevance of the course to the Employee’s profession.</p><p><strong>180.5</strong> The Employer will notify the Employee of whether or not their request for study leave has been approved within 7 days of the application being made.</p><p><strong>180.6</strong> Where the course of study is of relevance to the Employee’s employment, the Employer shall not withhold consent.</p><p><strong>180.7</strong> Where the number of staff seeking to take study leave at any one time causes operational difficulties, the Employer and Employee(s) concerned shall seek to reach agreement at a local level about the timeframe in which the leave is taken.</p><p><strong>180.8</strong> In all circumstances, the leave will be made available to the Employee(s) in the year in which application is made.</p><p><strong>180.9</strong> Any dispute arising under this clause 180 shall be resolved in accordance with the Dispute Settling Procedures.</p><p><strong>180.10</strong> Paid study leave pursuant to this clause does not accumulate from year to year.</p><p>Plain language terms: exam leave, education leave.</p>',14)])])}const c=t(r,[["render",n]]);export{m as __pageData,c as default};
